deckCss:
  *{box-sizing:border-box}
  html,body{margin:0;padding:0;background:#0a0a0b}
  :root{
    --bg:#0a0a0b;--surface:#141416;--surf2:#1c1c1f;--text:#fafafa;--muted:#a1a1a1;
    --line:rgba(250,250,250,.10);--line2:rgba(250,250,250,.17);
    --yellow:#ffc700;--run:#2aa8e6;--why:#5ec22e;--navy:#13294d;
    --eco-core:#ffc700;--eco-agent:#f97316;--eco-ui:#3b82f6;--eco-lens:#10b981;--eco-think:#8b5cf6;
    --sans:'Space Grotesk',-apple-system,system-ui,sans-serif;
    --mono:'JetBrains Mono',ui-monospace,SFMono-Regular,monospace;
  }
  @keyframes fpDelta{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:none}}
  @keyframes fpPanel{from{opacity:0;transform:translateX(54px)}to{opacity:1;transform:none}}
  @keyframes fpPop{from{opacity:0;transform:scale(.66)}to{opacity:1;transform:scale(1)}}
  @keyframes fpFoot{from{opacity:0;transform:translateY(-16px) scale(.25)}to{opacity:1;transform:translateY(0) scale(1)}}
  @keyframes fpDraw{from{stroke-dashoffset:var(--dash,1500)}to{stroke-dashoffset:0}}
  @keyframes fpFade{from{opacity:0}to{opacity:1}}
  @keyframes fpChip{from{opacity:0;transform:translateX(-24px)}to{opacity:1;transform:none}}
  @media (prefers-reduced-motion: no-preference){
    [data-deck-active] .fp-enter{animation:fpDelta .64s cubic-bezier(.2,.8,.2,1) both}
    [data-deck-active] .fp-panel{animation:fpPanel .62s cubic-bezier(.2,.8,.2,1) both}
    [data-deck-active] .fp-pop{animation:fpPop .54s cubic-bezier(.2,1.25,.4,1) both}
    [data-deck-active] .fp-foot{animation:fpFoot .5s cubic-bezier(.2,1.2,.4,1) both}
    [data-deck-active] .fp-draw{animation:fpDraw 1.2s ease both}
    [data-deck-active] .fp-fade{animation:fpFade .7s ease both}
    [data-deck-active] .fp-chip{animation:fpChip .52s cubic-bezier(.2,.9,.3,1) both}
  }
  [data-motion="off"] .fp-enter,[data-motion="off"] .fp-panel,[data-motion="off"] .fp-pop,
  [data-motion="off"] .fp-foot,[data-motion="off"] .fp-draw,[data-motion="off"] .fp-fade,
  [data-motion="off"] .fp-chip{animation:none !important;opacity:1 !important;transform:none !important;stroke-dashoffset:0 !important}

:root{--accent:#ffc700}
